(function(){document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll("[with-hover]").forEach(e=>{e.classList.add("with-hover")})}),window.VitralCSS={toggleHover:function(t,e=!0){document.querySelectorAll(t).forEach(o=>{e?o.classList.add("with-hover"):o.classList.remove("with-hover")})}}})();
